module calculator (
   // Inputs
   clk,
   reset,
   obf_a,
   b,
   op,

   // Outputs
   result
   );

   input clk, reset;
   input [3:0] obf_a, b;
   input op;
   output reg [3:0] result;

   always @ (posedge clk) begin
      if (reset) begin
         result <= 4'b0;
      end else begin
         if (op == 0) begin
            result <= obf_a + b;
         end else begin
            result <= obf_a - b;
         end
      end
   end

endmodule
